import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import AuthLayout from '../components/auth/AuthLayout';

const DEMO = {
  admin: { email: 'admin@college.edu', password: 'Admin@123' },
  student: { email: 'student@college.edu', password: 'Student@123' },
};

export default function Login() {
  const [role, setRole] = useState('student');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [adminSecret, setAdminSecret] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login, logout } = useAuth();
  const navigate = useNavigate();

  const switchRole = (r) => {
    setRole(r);
    setEmail('');
    setPassword('');
    setAdminSecret('');
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const data = await login(email, password, role, role === 'admin' ? adminSecret : undefined);
      if (role === 'admin' && data.user.role !== 'admin') {
        logout();
        setError('This account is not registered as an administrator.');
        return;
      }
      if (role === 'student' && data.user.role !== 'student') {
        logout();
        setError('This account is not registered as a student.');
        return;
      }
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout
      title="Sign In"
      subtitle="Enter your credentials to access the portal"
      footerLink={{ text: "Don't have an account?", to: '/signup', label: 'Sign up' }}
    >
      <div className="role-tabs">
        <button type="button" className={`role-tab ${role === 'student' ? 'active' : ''}`} onClick={() => switchRole('student')}>Student</button>
        <button type="button" className={`role-tab ${role === 'admin' ? 'active' : ''}`} onClick={() => switchRole('admin')}>Administrator</button>
      </div>

      {error && <div className="login-error">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Email</label>
          <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="name@college.edu" required autoComplete="email" />
        </div>
        <div className="form-group">
          <label>Password</label>
          <div className="input-wrap">
            <input type={showPass ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter password" required autoComplete="current-password" />
            <button type="button" className="toggle-pass" onClick={() => setShowPass(!showPass)}>{showPass ? 'Hide' : 'Show'}</button>
          </div>
        </div>

        {role === 'admin' && (
          <div className="form-group">
            <label>Administrator Access Code</label>
            <input type="password" value={adminSecret} onChange={e => setAdminSecret(e.target.value)} placeholder="Enter access code" required />
            <small className="field-hint">Required for administrator sign in</small>
          </div>
        )}

        <button type="submit" className="btn btn-primary btn-lg login-submit" disabled={loading}>
          {loading ? <><span className="spinner spinner-sm" /> Signing in...</> : 'Sign In'}
        </button>
      </form>

      <details className="demo-details">
        <summary>Demo credentials</summary>
        <div className="demo-cred-list">
          <div>
            <span>Student</span>
            <code>{DEMO.student.email}</code>
            <code>{DEMO.student.password}</code>
          </div>
          <div>
            <span>Admin (access code: Bus1010)</span>
            <code>{DEMO.admin.email}</code>
            <code>{DEMO.admin.password}</code>
          </div>
        </div>
      </details>
    </AuthLayout>
  );
}
